fn add_cors_headers(response: String, origin: String, cors_config: String) -> () {
    let response: Response = {
        let core: spikard::Response = serde_json::from_str(&response)
            .map_err(|e| magnus::Error::new(unsafe { Ruby::get_unchecked() }.exception_type_error(), e.to_string()))?;
        core.into()
    };
    let cors_config: CorsConfig = {
        let core: spikard::CorsConfig = serde_json::from_str(&cors_config)
            .map_err(|e| magnus::Error::new(unsafe { Ruby::get_unchecked() }.exception_type_error(), e.to_string()))?;
        core.into()
    };
    ()
}

